import React, {useState, useEffect} from 'react';
import { useHistory } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

// Add custom CSS for enhanced sidebar
const sidebarStyles = `
    @keyframes rotate {
        from { transform: rotate(0deg); }
        to { transform: rotate(360deg); }
    }
    
    @keyframes pulse {
        0%, 100% { opacity: 1; }
        50% { opacity: 0.5; }
    }

    /* Enhanced glass animations */
    @keyframes selectedGlow {
        0%, 100% { 
            box-shadow: 
                0 20px 50px rgba(245, 158, 11, 0.45),
                0 12px 25px rgba(251, 191, 36, 0.35),
                0 6px 15px rgba(252, 211, 77, 0.25),
                inset 0 2px 0 rgba(255, 255, 255, 0.4);
        }
        50% { 
            box-shadow: 
                0 25px 60px rgba(245, 158, 11, 0.55),
                0 15px 30px rgba(251, 191, 36, 0.45),
                0 8px 18px rgba(252, 211, 77, 0.35),
                inset 0 3px 0 rgba(255, 255, 255, 0.5);
        }
    }

    @keyframes glassFloat {
        0%, 100% { transform: translateY(0px); }
        50% { transform: translateY(-2px); }
    }

    @keyframes glassShimmer {
        0% { transform: translateX(-100%) skewX(-15deg); }
        100% { transform: translateX(200%) skewX(-15deg); }
    }

    @keyframes shimmer {
        0% { background-position: -200% 0; }
        100% { background-position: 200% 0; }
    }
    
    /* Glass Morphism Menu Items - Modern Design */
    .enhanced-admin-menu .ant-menu-item {
        border-radius: 18px !important;
        margin: 6px 8px !important;
        padding: 16px 20px !important;
        transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1) !important;
        background: linear-gradient(145deg, 
            rgba(255, 255, 255, 0.12) 0%, 
            rgba(255, 255, 255, 0.08) 25%,
            rgba(255, 255, 255, 0.05) 75%, 
            rgba(255, 255, 255, 0.02) 100%) !important;
        border: 2px solid rgba(255, 255, 255, 0.15) !important;
        backdrop-filter: blur(20px) saturate(180%) !important;
        -webkit-backdrop-filter: blur(20px) saturate(180%) !important;
        position: relative !important;
        overflow: hidden !important;
        display: flex !important;
        align-items: center !important;
        justify-content: flex-start !important;
        text-align: left !important;
        box-shadow: 
            0 8px 32px rgba(0, 0, 0, 0.12),
            0 4px 16px rgba(0, 0, 0, 0.08),
            inset 0 1px 0 rgba(255, 255, 255, 0.2),
