                                        <label className={`text-sm font-medium ${
                                            isDarkMode ? 'text-gray-300' : 'text-gray-700'
                                        }`}>
                                            Name
                                        </label>
                                        <div className={`p-3 rounded-lg ${
                                            isDarkMode ? 'bg-gray-700' : 'bg-gray-50'
                                        }`}>
                                            {selectedContact.name}
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <label className={`text-sm font-medium ${
                                            isDarkMode ? 'text-gray-300' : 'text-gray-700'
                                        }`}>
