                                        <div className={`p-3 rounded-lg ${
                                            isDarkMode ? 'bg-gray-700' : 'bg-gray-50'
                                        }`}>
                                            {new Date(selectedContact.createdAt || Date.now()).toLocaleDateString()}
                                        </div>
                                    </div>
                                </div>
                            </div>
                            
                            {/* Footer */}
                            <div className={`flex justify-end space-x-3 p-6 border-t ${
