                        {/* Bottom Section - Combined Collapse/Toggle Button */}
                        <div style={{ 
                            display: 'flex', 
                            justifyContent: 'center',
                            alignItems: 'center'
                        }}>
                            {/* Enhanced Combined Collapse/Toggle Button */}
